<?php

namespace App\Services;

use Twilio\Rest\Client;
use Twilio\Exceptions\TwilioException;
use Illuminate\Support\Facades\Log;

class TwilioSmsService
{
    protected $client;
    protected $fromNumber;

    public function __construct()
    {
        $accountSid = config('services.twilio.account_sid');
        $authToken = config('services.twilio.auth_token');
        $this->fromNumber = config('services.twilio.from_number');

        $this->client = new Client($accountSid, $authToken);
    }

    public function sendSms($to, $message)
    {
        try {
            $response = $this->client->messages->create(
                $to,
                [
                    'from' => $this->fromNumber,
                    'body' => $message
                ]
            );

            return [
                'success' => true,
                'message_sid' => $response->sid,
                'status' => $response->status,
                'data' => $response
            ];
        } catch (TwilioException $e) {
            Log::error('Twilio SMS Error: ' . $e->getMessage());

            return [
                'success' => false,
                'error' => $e->getMessage(),
                'code' => $e->getCode()
            ];
        } catch (\Exception $e) {
            Log::error('SMS Service Error: ' . $e->getMessage());

            return [
                'success' => false,
                'error' => $e->getMessage()
            ];
        }
    }

    public function sendBulkSms(array $recipients, $message)
    {
        $results = [];

        foreach ($recipients as $recipient) {
            $results[] = $this->sendSms($recipient, $message);
        }

        return $results;
    }

    public function getMessageStatus($messageSid)
    {
        try {
            $message = $this->client->messages($messageSid)->fetch();

            return [
                'success' => true,
                'status' => $message->status,
                'to' => $message->to,
                'from' => $message->from,
                'date_sent' => $message->dateSent,
                'error_code' => $message->errorCode,
                'error_message' => $message->errorMessage
            ];
        } catch (TwilioException $e) {
            Log::error('Twilio Status Check Error: ' . $e->getMessage());

            return [
                'success' => false,
                'error' => $e->getMessage()
            ];
        }
    }
}